const { chromium } = require('playwright');
const path = require('path');

(async () => {
    const browser = await chromium.launch({ headless: true });
    const page = await browser.newPage();

    const errors = [];
    const consoleLogs = [];

    page.on('console', msg => {
        consoleLogs.push(`[${msg.type()}] ${msg.text()}`);
    });
    page.on('pageerror', err => {
        errors.push(`PAGE ERROR: ${err.message}`);
    });

    const filePath = path.resolve('C:\\Users\\PC\\Documents\\AntiGravity\\Projects\\SwimLanes\\Swimlane_App.html');
    await page.goto(`file:///${filePath.replace(/\\/g, '/')}`);
    await page.waitForTimeout(3000);

    const screenshot = 'C:\\Users\\PC\\Documents\\AntiGravity\\Projects\\SwimLanes\\verify-screenshot.png';
    await page.screenshot({ path: screenshot, fullPage: false });

    const bodyText = await page.evaluate(() => document.body.innerText.substring(0, 500));
    const hasContent = await page.evaluate(() => {
        const container = document.getElementById('journal-container');
        return container ? container.innerHTML.length : 0;
    });

    console.log('=== PAGE ERRORS ===');
    errors.forEach(e => console.log(e));
    if (errors.length === 0) console.log('(none)');

    console.log('\n=== CONSOLE LOGS ===');
    consoleLogs.forEach(l => console.log(l));
    if (consoleLogs.length === 0) console.log('(none)');

    console.log('\n=== BODY TEXT (first 500 chars) ===');
    console.log(bodyText);

    console.log('\n=== journal-container innerHTML length ===');
    console.log(hasContent);

    console.log('\nScreenshot saved to:', screenshot);

    await browser.close();
})();

